import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
} from 'chart.js';
import { Bar, Pie, Line } from 'react-chartjs-2';
import {
  UsersIcon,
  DocumentTextIcon,
  MapPinIcon,
  ExclamationTriangleIcon,
  ArrowTrendingUpIcon,
  CheckCircleIcon,
  UserIcon,
  ArrowRightOnRectangleIcon,
  CpuChipIcon,
  ChartBarIcon
} from '@heroicons/react/24/outline';
import MLPredictionTab from '../components/admin/MLPredictionTab';
import ComplaintManagement from '../components/admin/ComplaintManagement';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
);

const AdminDashboard = () => {
  const [user, setUser] = useState(null);
  const [selectedTimeRange, setSelectedTimeRange] = useState('7d');
  const [activeTab, setActiveTab] = useState('overview');
  const navigate = useNavigate();

  useEffect(() => {
    // Check if user is logged in and is admin
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    const user = JSON.parse(userData);
    if (user.userType !== 'admin') {
      navigate('/dashboard'); // Redirect non-admin users
      return;
    }

    setUser(user);
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  // Sample data for charts
  const complaintsByCategory = {
    labels: ['Infrastructure', 'Sanitation', 'Water Supply', 'Roads', 'Public Safety', 'Electricity'],
    datasets: [
      {
        label: 'Number of Complaints',
        data: [45, 38, 32, 28, 25, 20],
        backgroundColor: [
          'rgba(99, 102, 241, 0.9)',  // Indigo
          'rgba(34, 197, 94, 0.9)',   // Green
          'rgba(59, 130, 246, 0.9)',  // Blue
          'rgba(251, 146, 60, 0.9)',  // Orange
          'rgba(168, 85, 247, 0.9)',  // Purple
          'rgba(236, 72, 153, 0.9)'   // Pink
        ],
        borderColor: [
          'rgba(99, 102, 241, 1)',
          'rgba(34, 197, 94, 1)',
          'rgba(59, 130, 246, 1)',
          'rgba(251, 146, 60, 1)',
          'rgba(168, 85, 247, 1)',
          'rgba(236, 72, 153, 1)'
        ],
        borderWidth: 2,
        borderRadius: 8,
        borderSkipped: false,
      },
    ],
  };

  const complaintsByStatus = {
    labels: ['Pending', 'In Progress', 'Resolved', 'Rejected'],
    datasets: [
      {
        data: [30, 45, 120, 5],
        backgroundColor: [
          'rgba(251, 191, 36, 0.9)',  // Yellow
          'rgba(59, 130, 246, 0.9)',  // Blue
          'rgba(34, 197, 94, 0.9)',   // Green
          'rgba(239, 68, 68, 0.9)'    // Red
        ],
        borderColor: [
          'rgba(251, 191, 36, 1)',
          'rgba(59, 130, 246, 1)',
          'rgba(34, 197, 94, 1)',
          'rgba(239, 68, 68, 1)'
        ],
        borderWidth: 2,
        borderRadius: 8,
        borderSkipped: false,
      },
    ],
  };

  const weeklyTrends = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Complaints Received',
        data: [12, 19, 15, 25, 22, 30, 18],
        borderColor: 'rgba(99, 102, 241, 1)',
        backgroundColor: 'rgba(99, 102, 241, 0.1)',
        tension: 0.4,
        fill: true,
        pointBackgroundColor: 'rgba(99, 102, 241, 1)',
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
        pointRadius: 6,
        pointHoverRadius: 8,
      },
      {
        label: 'Complaints Resolved',
        data: [8, 12, 10, 18, 15, 25, 12],
        borderColor: 'rgba(34, 197, 94, 1)',
        backgroundColor: 'rgba(34, 197, 94, 0.1)',
        tension: 0.4,
        fill: true,
        pointBackgroundColor: 'rgba(34, 197, 94, 1)',
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
        pointRadius: 6,
        pointHoverRadius: 8,
      },
    ],
  };

  const severityDistribution = {
    labels: ['Low', 'Medium', 'High', 'Critical'],
    datasets: [
      {
        data: [60, 80, 40, 20],
        backgroundColor: [
          'rgba(34, 197, 94, 0.9)',   // Green
          'rgba(251, 191, 36, 0.9)',  // Yellow
          'rgba(251, 146, 60, 0.9)',  // Orange
          'rgba(239, 68, 68, 0.9)'    // Red
        ],
        borderColor: [
          'rgba(34, 197, 94, 1)',
          'rgba(251, 191, 36, 1)',
          'rgba(251, 146, 60, 1)',
          'rgba(239, 68, 68, 1)'
        ],
        borderWidth: 2,
        borderRadius: 8,
        borderSkipped: false,
      },
    ],
  };

  // Enhanced chart options
  const barChartOptions = {
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        backgroundColor: 'rgba(17, 24, 39, 0.9)',
        titleColor: '#fff',
        bodyColor: '#fff',
        borderColor: 'rgba(99, 102, 241, 0.5)',
        borderWidth: 1,
        padding: 12,
        displayColors: true,
        callbacks: {
          label: function(context) {
            return context.dataset.label + ': ' + context.parsed.y + ' complaints';
          }
        }
      }
    },
    scales: {
      x: {
        grid: {
          display: false,
        },
        ticks: {
          font: {
            size: 12,
            weight: '500'
          },
          color: '#6b7280'
        }
      },
      y: {
        beginAtZero: true,
        grid: {
          color: 'rgba(229, 231, 235, 0.5)',
          drawBorder: false,
        },
        ticks: {
          font: {
            size: 12,
            weight: '500'
          },
          color: '#6b7280'
        }
      }
    },
    animation: {
      duration: 1000,
      easing: 'easeInOutQuart'
    }
  };

  const pieChartOptions = {
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        position: 'bottom',
        labels: {
          padding: 20,
          font: {
            size: 12,
            weight: '500'
          },
          color: '#374151'
        }
      },
      tooltip: {
        backgroundColor: 'rgba(17, 24, 39, 0.9)',
        titleColor: '#fff',
        bodyColor: '#fff',
        borderColor: 'rgba(99, 102, 241, 0.5)',
        borderWidth: 1,
        padding: 12,
        displayColors: true,
        callbacks: {
          label: function(context) {
            const total = context.dataset.data.reduce((a, b) => a + b, 0);
            const percentage = ((context.parsed / total) * 100).toFixed(1);
            return context.label + ': ' + context.parsed + ' (' + percentage + '%)';
          }
        }
      }
    },
    animation: {
      animateRotate: true,
      animateScale: true,
      duration: 1000,
      easing: 'easeInOutQuart'
    }
  };

  const lineChartOptions = {
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          padding: 20,
          font: {
            size: 12,
            weight: '500'
          },
          color: '#374151',
          usePointStyle: true,
          pointStyle: 'circle'
        }
      },
      tooltip: {
        backgroundColor: 'rgba(17, 24, 39, 0.9)',
        titleColor: '#fff',
        bodyColor: '#fff',
        borderColor: 'rgba(99, 102, 241, 0.5)',
        borderWidth: 1,
        padding: 12,
        displayColors: true,
        mode: 'index',
        intersect: false
      }
    },
    scales: {
      x: {
        grid: {
          display: false,
        },
        ticks: {
          font: {
            size: 12,
            weight: '500'
          },
          color: '#6b7280'
        }
      },
      y: {
        beginAtZero: true,
        grid: {
          color: 'rgba(229, 231, 235, 0.5)',
          drawBorder: false,
        },
        ticks: {
          font: {
            size: 12,
            weight: '500'
          },
          color: '#6b7280'
        }
      }
    },
    interaction: {
      mode: 'nearest',
      axis: 'x',
      intersect: false
    },
    animation: {
      duration: 1000,
      easing: 'easeInOutQuart'
    }
  };

  const stats = [
    { name: 'Total Users', value: '1,234', icon: UsersIcon, change: '+12%', changeType: 'increase' },
    { name: 'Total Complaints', value: '2,456', icon: DocumentTextIcon, change: '+8%', changeType: 'increase' },
    { name: 'Active Hotspots', value: '15', icon: MapPinIcon, change: '-3%', changeType: 'decrease' },
    { name: 'Critical Issues', value: '8', icon: ExclamationTriangleIcon, change: '+2', changeType: 'increase' },
  ];

  const hotspots = [
    { id: 1, area: 'Downtown District', complaints: 45, severity: 'High', trend: 'up' },
    { id: 2, area: 'Industrial Zone', complaints: 32, severity: 'Medium', trend: 'stable' },
    { id: 3, area: 'Residential North', complaints: 28, severity: 'Low', trend: 'down' },
    { id: 4, area: 'Commercial Center', complaints: 25, severity: 'High', trend: 'up' },
    { id: 5, area: 'University Area', complaints: 18, severity: 'Medium', trend: 'stable' },
  ];

  const recentActivity = [
    { id: 1, action: 'New complaint submitted', user: 'John Doe', time: '2 minutes ago', type: 'complaint' },
    { id: 2, action: 'Hotspot detected', area: 'Downtown District', time: '15 minutes ago', type: 'hotspot' },
    { id: 3, action: 'Complaint resolved', id: 'CMP001', time: '1 hour ago', type: 'resolved' },
    { id: 4, action: 'Critical issue escalated', severity: 'High', time: '2 hours ago', type: 'critical' },
    { id: 5, action: 'New user registered', user: 'Jane Smith', time: '3 hours ago', type: 'user' },
  ];

  const getTrendIcon = (trend) => {
    switch (trend) {
      case 'up':
        return <ArrowTrendingUpIcon className="h-4 w-4 text-red-500" />;
      case 'down':
        return <ArrowTrendingUpIcon className="h-4 w-4 text-green-500 transform rotate-180" />;
      default:
        return <div className="h-4 w-4 bg-gray-400 rounded-full" />;
    }
  };

  const getSeverityBadge = (severity) => {
    const colors = {
      'Low': 'bg-green-100 text-green-800',
      'Medium': 'bg-yellow-100 text-yellow-800',
      'High': 'bg-orange-100 text-orange-800',
      'Critical': 'bg-red-100 text-red-800'
    };
    return `inline-flex px-2 py-1 text-xs font-semibold rounded-full ${colors[severity]}`;
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Navigation */}
      <nav className="bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <Link to="/" className="text-2xl font-bold text-blue-600">Urban Insights</Link>
              <span className="ml-4 text-sm text-gray-500">Admin Panel</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-2">
                <UserIcon className="h-5 w-5 text-gray-400" />
                <span className="text-sm font-medium text-gray-700">
                  {user?.name || 'Admin'}
                </span>
              </div>
              <button
                onClick={handleLogout}
                className="flex items-center space-x-2 text-gray-700 hover:text-red-600 px-3 py-2 rounded-md text-sm font-medium transition-colors"
              >
                <ArrowRightOnRectangleIcon className="h-5 w-5" />
                <span>Logout</span>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900">Admin Dashboard</h1>
          <p className="text-gray-600 mt-2">Monitor and manage community issues system-wide</p>
        </div>

        {/* Tab Navigation */}
        <div className="border-b border-gray-200 mb-8">
          <nav className="-mb-px flex space-x-8">
            {[
              { id: 'overview', name: 'Analytics Overview', icon: ChartBarIcon },
              { id: 'complaint-management', name: 'Complaint Management', icon: ExclamationTriangleIcon },
              { id: 'ml-prediction', name: 'ML Predictions', icon: CpuChipIcon }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`${activeTab === tab.id
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                  } whitespace-nowrap py-2 px-1 border-b-2 font-medium text-sm flex items-center`}
              >
                <tab.icon className="h-4 w-4 mr-2" />
                {tab.name}
              </button>
            ))}
          </nav>
        </div>

        {/* Tab Content */}
        {activeTab === 'ml-prediction' ? (
          <MLPredictionTab />
        ) : activeTab === 'complaint-management' ? (
          <ComplaintManagement />
        ) : (
          <div>
            {/* Time Range Selector */}
            <div className="mb-6 flex justify-end">
              <select
                value={selectedTimeRange}
                onChange={(e) => setSelectedTimeRange(e.target.value)}
                className="block pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm rounded-md"
              >
                <option value="24h">Last 24 Hours</option>
                <option value="7d">Last 7 Days</option>
                <option value="30d">Last 30 Days</option>
                <option value="90d">Last 90 Days</option>
              </select>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              {stats.map((stat) => (
                <div key={stat.name} className="bg-white overflow-hidden shadow rounded-lg">
                  <div className="p-5">
                    <div className="flex items-center">
                      <div className="flex-shrink-0 bg-blue-500 rounded-md p-3">
                        <stat.icon className="h-6 w-6 text-white" />
                      </div>
                      <div className="ml-5 w-0 flex-1">
                        <dl>
                          <dt className="text-sm font-medium text-gray-500 truncate">{stat.name}</dt>
                          <dd className="flex items-baseline">
                            <div className="text-2xl font-semibold text-gray-900">{stat.value}</div>
                            <div className={`ml-2 flex items-baseline text-sm font-semibold ${stat.changeType === 'increase' ? 'text-green-600' : 'text-red-600'
                              }`}>
                              {stat.change}
                            </div>
                          </dd>
                        </dl>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Charts Row 1 */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
              {/* Complaints by Category */}
              <div className="bg-white p-6 shadow-lg rounded-xl border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                  <ChartBarIcon className="h-5 w-5 mr-2 text-indigo-500" />
                  Complaints by Category
                </h3>
                <Bar data={complaintsByCategory} options={barChartOptions} />
              </div>

              {/* Complaints by Status */}
              <div className="bg-white p-6 shadow-lg rounded-xl border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                  <DocumentTextIcon className="h-5 w-5 mr-2 text-blue-500" />
                  Complaints by Status
                </h3>
                <Pie data={complaintsByStatus} options={pieChartOptions} />
              </div>
            </div>

            {/* Charts Row 2 */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
              {/* Weekly Trends */}
              <div className="bg-white p-6 shadow-lg rounded-xl border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                  <ArrowTrendingUpIcon className="h-5 w-5 mr-2 text-green-500" />
                  Weekly Trends
                </h3>
                <Line data={weeklyTrends} options={lineChartOptions} />
              </div>

              {/* Severity Distribution */}
              <div className="bg-white p-6 shadow-lg rounded-xl border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
                  <ExclamationTriangleIcon className="h-5 w-5 mr-2 text-orange-500" />
                  Severity Distribution
                </h3>
                <Pie data={severityDistribution} options={pieChartOptions} />
              </div>
            </div>

            {/* Hotspots and Activity */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Hotspot Areas */}
              <div className="bg-white shadow rounded-lg">
                <div className="px-4 py-5 sm:p-6">
                  <h3 className="text-lg leading-6 font-medium text-gray-900 mb-4">Hotspot Areas</h3>
                  <div className="overflow-hidden">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead>
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Area
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Complaints
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Severity
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Trend
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {hotspots.map((hotspot) => (
                          <tr key={hotspot.id}>
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                              {hotspot.area}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {hotspot.complaints}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className={getSeverityBadge(hotspot.severity)}>
                                {hotspot.severity}
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              {getTrendIcon(hotspot.trend)}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>

              {/* Recent Activity */}
              <div className="bg-white shadow rounded-lg">
                <div className="px-4 py-5 sm:p-6">
                  <h3 className="text-lg leading-6 font-medium text-gray-900 mb-4">Recent Activity</h3>
                  <div className="flow-root">
                    <ul className="-my-5 divide-y divide-gray-200">
                      {recentActivity.map((activity) => (
                        <li key={activity.id} className="py-4">
                          <div className="flex items-center space-x-4">
                            <div className="flex-shrink-0">
                              {activity.type === 'complaint' && <DocumentTextIcon className="h-8 w-8 text-blue-500" />}
                              {activity.type === 'hotspot' && <MapPinIcon className="h-8 w-8 text-red-500" />}
                              {activity.type === 'resolved' && <CheckCircleIcon className="h-8 w-8 text-green-500" />}
                              {activity.type === 'critical' && <ExclamationTriangleIcon className="h-8 w-8 text-orange-500" />}
                              {activity.type === 'user' && <UsersIcon className="h-8 w-8 text-purple-500" />}
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-gray-900">{activity.action}</p>
                              <p className="text-sm text-gray-500">
                                {activity.user || activity.area || activity.id || activity.severity} • {activity.time}
                              </p>
                            </div>
                          </div>
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
